  ('promotion-64311456-moex-00065', 'promotion-64311456', 'promotion-64311456-moex-112-3082b5f1', 'sub-promotion-64311456-04', NULL, 'single_choice', '關於國家賠償之協議先行程序，下列敘述何者正確？', '["請求國家賠償時，得以言詞向賠償義務機關提出請求", "國家賠償協議成立時，應作成協議書，該項協議書須經公證後，始得為執行名義", "賠償義務機關自開始協議之日起逾60日協議不成立時，請求權人得提起損害賠償之訴", "請求國家賠償時，法院得依聲請為假扣押，命賠償義務機關暫先支付精神慰撫金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "106", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會行政"}'::jsonb, NULL),
  ('promotion-64311456-moex-00066', 'promotion-64311456', 'promotion-64311456-moex-112-3082b5f1', 'sub-promotion-64311456-04', NULL, 'single_choice', '關於行政機關將違法行政處分轉換為與原處分具有相同實質及程序要件之其他處分，下列敘述何 者錯誤？', '["行政處分若違反程序或方式規定，或有顯然錯誤，應屬得補正或更正之範圍，非屬得轉換之瑕疵", "轉換對公益有重大危害或對當事人更不利者，不得轉換", "轉換後之行政處分自始取代違法之原處分，故行政機關不須為轉換之表示", "羈束處分不得轉換為裁量處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "106", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會行政"}'::jsonb, NULL),
  ('promotion-64311456-moex-00067', 'promotion-64311456', 'promotion-64311456-moex-112-3082b5f1', 'sub-promotion-64311456-04', NULL, 'single_choice', '下列何者非屬行政事實行為？', '["行政鑑定", "道路上之限速標誌", "以物理上強制力所為之執行行為", "陳情之回覆"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "106", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會行政"}'::jsonb, NULL),
  ('promotion-64311456-moex-00068', 'promotion-64311456', 'promotion-64311456-moex-112-3082b5f1', 'sub-promotion-64311456-04', NULL, 'single_choice', '關於公法上法律關係得以契約設定、變更或消滅之規定，下列敘述何者錯誤？', '["得以契約標的具有公法性質，作為行政契約判斷標準之一", "契約之內容以執行公法法規為目的，屬公法契約", "行政機關原則上得以行政處分作為行使契約上權利之手段", "二個以上之公權力主體得締結行政契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "106", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會行政"}'::jsonb, NULL),
  ('promotion-64311456-moex-00069', 'promotion-64311456', 'promotion-64311456-moex-112-3082b5f1', 'sub-promotion-64311456-04', NULL, 'single_choice', '關於行政罰之處罰對象，下列敘述何者錯誤？', '["多數人故意共同實施因身分或其他特定關係成立之違反行政法上義務行為，其無此身分或特定 關係者，不受處罰", "地方行政機關得為裁罰對象", "私法人之董事因執行其職務之行為，致使私法人違反行政法上義務應受處罰者，該董事如有重 大過失，原則上應並受同一規定罰鍰之處罰", "多數人故意共同實施違反行政法上義務之行為，應依其行為情節之輕重，分別處罰之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "106", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會行政"}'::jsonb, NULL),
  ('promotion-64311456-moex-00070', 'promotion-64311456', 'promotion-64311456-moex-112-3082b5f1', 'sub-promotion-64311456-04', NULL, 'single_choice', '依行政執行法與司法實務見解，關於行政執行聲明異議之敘述，下列何者正確？', '["對具行政處分性質之執行命令不服，經聲明異議程序，仍有不服時，聲明異議人可直接提起撤 銷訴訟", "對具行政處分性質之執行命令不服，得擇一聲明異議或提起訴願", "對具行政處分性質之執行命令不服，經聲明異議程序仍有不服者，應依法踐行訴願程序", "行政執行貴在效率，聲明異議為特別之救濟程序，即不得再循一般爭訟程序請求救濟 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "106", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會行政"}'::jsonb, NULL),
  ('promotion-64311456-moex-00071', 'promotion-64311456', 'promotion-64311456-moex-112-3082b5f1', 'sub-promotion-64311456-04', NULL, 'single_choice', '關於行政程序法之迴避，下列敘述何者錯誤？', '["公務員在行政程序中發現事件當事人曾為三等親內之姻親，應自行迴避", "公務員在稅務事件中發現當事人為其所厭惡之國小導師，自認執行職務有偏頗之虞，向所屬機 關自請迴避，機關認為不符應自行迴避事由，應否准之", "當事人有具體事證，足認承辦公務員執行職務有偏頗之虞，得向公務員所屬機關申請迴避", "公務員所屬機關之長官於公務員有應自行迴避之事由而不迴避，而未經當事人申請迴避時，應 依職權命其迴避"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "106", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會行政"}'::jsonb, NULL),
  ('promotion-64311456-moex-00072', 'promotion-64311456', 'promotion-64311456-moex-112-3082b5f1', 'sub-promotion-64311456-04', NULL, 'single_choice', '下列何者得提起訴願救濟？', '["公務人員對公務人員保障暨培訓委員會之復審決定不服", "會計師不服懲戒處分，向財政部會計師覆審委員會聲請覆審，對於該覆審決議不服", "義務人對具有行政處分性質之執行命令不服，依行政執行法聲明異議經上級機關駁回異議", "納稅義務人對於課稅處分不服，依稅捐稽徵法申請復查，對於復查決定不服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "106", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會行政"}'::jsonb, NULL),
  ('promotion-64311456-moex-00073', 'promotion-64311456', 'promotion-64311456-moex-112-3082b5f1', 'sub-promotion-64311456-04', NULL, 'single_choice', '關於訴願當事人適格之敘述，下列何者錯誤？', '["訴願人具有訴願權能，得以自己名義提起訴願者，具有當事人適格", "因行政處分遭受生活上不便利者，皆具有訴願當事人適格", "行政處分相對人以外之第三人亦可能具訴願當事人適格", "訴願當事人是否適格，受理訴願機關應依職權調查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "106", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會行政"}'::jsonb, NULL)
